import type { FilterSegment as QueryFilterSegment } from '@dynatrace-sdk/client-query';

import type { UISegment } from './UISegments.types.js';

export type SegmentSelectorReducerActions =
  | {
      type: 'add';
      payload: { segments?: QueryFilterSegment; isPlaceholder: boolean };
    }
  | {
      type: 'remove';
      payload: { id: string };
    }
  | {
      type: 'removeAll';
    }
  | {
      type: 'update';
      payload: {
        oldSegment: QueryFilterSegment;
        newSegment: QueryFilterSegment;
      };
    }
  | { type: 'clearPlaceholder' }
  | {
      type: 'setArrayIdentifierError';
      payload: { hasError: boolean; id: string };
    }
  | {
      type: 'setUISegments';
      payload: {
        uiSegments: SegmentSelectorUIState['uiSegments'];
        hasSelection?: boolean;
      };
    };

export type SegmentSelectorUIState = {
  uiSegments: UISegment[];
  hasSelection: boolean;
  readOnly?: boolean;
  focusedSegmentId?: string;
  isTouched?: boolean;
  arrayIdentifierErrorIds?: string[];
};

export function segmentsUIReducer(
  state: SegmentSelectorUIState,
  action: SegmentSelectorReducerActions,
): SegmentSelectorUIState {
  const { type } = action;

  switch (type) {
    case 'add': {
      const { segments: segment, isPlaceholder } = action.payload;

      if (segment && !isPlaceholder) {
        return {
          ...state,
          isTouched: true,
          hasSelection: true,
          uiSegments: [...state.uiSegments, { ...segment }],
          focusedSegmentId: segment.id,
        };
      }

      const placeholderId = crypto.randomUUID();

      return {
        ...state,
        hasSelection: true,
        uiSegments: [
          ...state.uiSegments,
          {
            id: placeholderId,
            isPlaceholder: true,
          },
        ],
      };
    }
    case 'remove': {
      const { id } = action.payload;
      const newSegments = state.uiSegments.filter(
        (uiSegment) => id !== uiSegment.id,
      );
      const arrayIdentifierErrorIds = state.arrayIdentifierErrorIds?.filter(
        (errorId) => errorId !== id,
      );

      if (newSegments.length === 0) {
        return {
          isTouched: true,
          hasSelection: true,
          uiSegments: [
            {
              id: crypto.randomUUID(),
              isPlaceholder: true,
            },
          ],
          arrayIdentifierErrorIds: [],
        };
      }

      return {
        isTouched: true,
        hasSelection: true,
        uiSegments: newSegments,
        arrayIdentifierErrorIds,
      };
    }
    case 'removeAll': {
      return {
        isTouched: true,
        hasSelection: false,
        uiSegments: [
          {
            id: crypto.randomUUID(),
            isPlaceholder: true,
          },
        ],
        arrayIdentifierErrorIds: [],
      };
    }
    case 'update': {
      const { newSegment, oldSegment } = action.payload;

      const index = state.uiSegments.findIndex(
        (uiSegment) => uiSegment.id === oldSegment.id,
      );

      if (index !== -1) {
        const updatedSegments = [...state.uiSegments];
        updatedSegments[index] = { ...newSegment };

        return {
          ...state,
          isTouched: true,
          hasSelection: state.uiSegments.length > 0,
          uiSegments: updatedSegments,
          focusedSegmentId: newSegment.id,
        };
      }

      return state;
    }
    case 'clearPlaceholder': {
      const actualSegmentsOnly = state.uiSegments.filter(
        (uiSegment) => !uiSegment.isPlaceholder,
      );

      return {
        ...state,
        uiSegments: actualSegmentsOnly,
      };
    }
    case 'setUISegments': {
      const { payload } = action;
      const { hasSelection, uiSegments } = payload;

      return {
        ...state,
        isTouched: false,
        uiSegments,
        hasSelection: hasSelection ?? state.hasSelection,
      };
    }
    case 'setArrayIdentifierError': {
      const { payload } = action;
      const { hasError, id } = payload;

      if (hasError) {
        const newState = {
          ...state,
          arrayIdentifierErrorIds: state.arrayIdentifierErrorIds ?? [],
        };
        newState.arrayIdentifierErrorIds.push(id);
        return newState;
      }

      const newState = { ...state };
      newState.arrayIdentifierErrorIds?.filter((errorId) => errorId !== id);
      return newState;
    }
  }
}
